	Text     = "Change Rarity",
	Values   = RARITY_OVERRIDES,
	Default  = "Default",
	Callback = function(v)
		state.selectedRarity = v
	end,
})

OptionsGroup:AddDivider()

local StatusLabel = OptionsGroup:AddLabel("Status: Inactive", true)

OptionsGroup:AddToggle("AutoSpawn", {
	Text     = "Auto-Create",
	Default  = false,
	Callback = function(v)
		if v and not state.selectedPetLabel then
			StatusLabel:SetText("Status: No pet selected.")
			Options.AutoSpawn:SetValue(false)
			return
		end
		state.autoSpawn = v
		StatusLabel:SetText(v and "Status: Creating..." or "Status: Inactive")
	end,
})

OptionsGroup:AddSlider("SpawnDelay", {
	Text     = "Pet Creation Delay (Seconds)",
	Min      = 0.1,
